const output = $input.first().json.output || '';

const START = '[PERFIL_COMPLETO]';
const END   = '[/PERFIL_COMPLETO]';
const s = output.indexOf(START);
const e = output.indexOf(END);

let cleanText = output.trim();
let hasProfile = false;
let profile = null;

if (s !== -1 && e !== -1) {
  cleanText = output.substring(0, s).trim();
  const jsonStr = output.substring(s + START.length, e).trim();
  try {
    const raw = JSON.parse(jsonStr);
    hasProfile = true;

    const actMap = {
      'sedentario':'sedentary','sedentary':'sedentary',
      'poco activo':'lightly_active','lightly_active':'lightly_active',
      'moderadamente activo':'moderately_active','moderately_active':'moderately_active',
      'muy activo':'very_active','very_active':'very_active',
      'extremadamente activo':'extra_active','extra_active':'extra_active'
    };
    const goalMap = {
      'bajar de peso':'lose_weight','perder peso':'lose_weight','lose_weight':'lose_weight',
      'ganar musculo':'gain_muscle','gain_muscle':'gain_muscle',
      'mantener':'maintain','maintain':'maintain',
      'recomposicion':'recomposition','recomposition':'recomposition'
    };
    const genderMap = {'masculino':'male','male':'male','femenino':'female','female':'female'};
    const budgetMap = {
      'economico':'low','low':'low',
      'moderado':'medium','medium':'medium',
      'sin restriccion':'high','alto':'high','high':'high'
    };
    const fitnessMap = {
      'principiante':'beginner','beginner':'beginner',
      'intermedio':'intermediate','intermediate':'intermediate',
      'avanzado':'advanced','advanced':'advanced'
    };

    const toArr = (v) => {
      if (!v || v === 'ninguna' || v === 'ninguno') return '[]';
      if (Array.isArray(v)) {
        const filtered = v.filter(x => x && x !== 'ninguna' && x !== 'ninguno');
        return JSON.stringify(filtered);
      }
      return JSON.stringify([v]);
    };

    profile = {
      gender:   genderMap[(raw.genero||'').toLowerCase()] || 'male',
      age:      parseInt(raw.edad) || 25,
      height_cm: parseFloat(raw.altura_cm) || 170,
      weight_kg: parseFloat(raw.peso_kg) || 70,
      activity_level: actMap[(raw.actividad||'').toLowerCase()] || 'moderately_active',
      fitness_level:  fitnessMap[(raw.fitness||'').toLowerCase()] || 'beginner',
      goal: goalMap[(raw.objetivo||'').toLowerCase()] || 'lose_weight',
      dietary_restrictions: toArr(raw.restricciones),
      food_allergies:  toArr(raw.alergias),
      disliked_foods:  toArr(raw.disgustos),
      injuries:        toArr(raw.lesiones),
      available_equipment: toArr(raw.equipamiento),
      training_days_per_week: parseInt(raw.dias_entrenamiento) || 3,
      meal_count: parseInt(raw.comidas_dia) || 3,
      local_culture: raw.cultura || 'colombiana',
      budget_level: budgetMap[(raw.presupuesto||'').toLowerCase()] || 'medium',
      country:  raw.pais  || null,
      city:     raw.ciudad || null,
      document_number: (raw.documento && raw.documento !== 'prefiero no dar') ? raw.documento : null
    };

    // Construir resumen legible del perfil para mostrar al usuario
    const goalLabels = { lose_weight:'Bajar de peso', gain_muscle:'Ganar músculo', maintain:'Mantener peso', recomposition:'Recomposición' };
    const actLabels  = { sedentary:'Sedentario', lightly_active:'Poco activo', moderately_active:'Moderadamente activo', very_active:'Muy activo', extra_active:'Extremadamente activo' };
    const fitLabels  = { beginner:'Principiante', intermediate:'Intermedio', advanced:'Avanzado' };

    const restrictions = JSON.parse(profile.dietary_restrictions);
    const restrictStr  = restrictions.length > 0 ? restrictions.join(', ') : 'Ninguna';

    const profileSummary = [
      '',
      `🎯 *Objetivo:* ${goalLabels[profile.goal] || profile.goal}`,
      `⚖️ *Peso:* ${profile.weight_kg} kg | *Altura:* ${profile.height_cm} cm`,
      `🏃 *Actividad:* ${actLabels[profile.activity_level] || profile.activity_level}`,
      `💪 *Nivel fitness:* ${fitLabels[profile.fitness_level] || profile.fitness_level}`,
      `🍽️ *Comidas/día:* ${profile.meal_count} | *Días entreno/sem:* ${profile.training_days_per_week}`,
      `🚫 *Restricciones:* ${restrictStr}`,
    ].join('\n');

    cleanText = (cleanText || '¡Perfil completado! Aquí tienes tu resumen:') + profileSummary;

  } catch(e) {
    hasProfile = false;
  }
}

const userId = $('Check User & Membership').item.json.user_id;
const chatId = $('Set User Context').item.json.chatId;

return [{ json: { cleanText, hasProfile, profile, userId, chatId } }];

// Always produce output regardless of whether the token matched.
// Check Migration Token returns [] when no match — this would stop the flow.
const rows = $input.all();
const match = rows.length > 0 && rows[0].json && rows[0].json.id;
if (match) {
  return [{ json: { ...rows[0].json, migration_match: true } }];
}
return [{ json: { id: null, migration_match: false } }];

// Build Context v2 — assembles dynamic context + full system prompt for AI Agent
const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Bogota' });

const profileRows = $('Load User Profile').all();
const profile = profileRows.length > 0 ? profileRows[0].json : {};
const firstName = profile.first_name || $('Check User & Membership').item.json.first_name || 'Usuario';

const caloricTarget  = profile.caloric_target   || null;
const proteinTarget  = profile.protein_target_g  || null;
const carbTarget     = profile.carb_target_g     || null;
const fatTarget      = profile.fat_target_g      || null;
const tdee           = profile.tdee              || null;
const bmr            = profile.bmr               || null;
const currentWeight  = profile.weight_kg         || null;
const targetWeight   = profile.target_weight || profile.goal_target_weight || null;
const height         = profile.height_cm         || null;
const age            = profile.age               || null;
const gender         = profile.gender            || null;
const activityLevel  = profile.activity_level    || null;
const goalType       = profile.goal_type || profile.active_goal_type || null;
const membershipStatus = profile.membership_status || null;

let profileParts = [];
if (firstName)        profileParts.push(`Nombre: ${firstName}`);
if (currentWeight)    profileParts.push(`Peso actual: ${currentWeight}kg`);
if (targetWeight)     profileParts.push(`Meta de peso: ${targetWeight}kg`);
if (height)           profileParts.push(`Talla: ${height}cm`);
if (age)              profileParts.push(`Edad: ${age} años`);
if (gender)           profileParts.push(`Género: ${gender}`);
if (activityLevel)    profileParts.push(`Actividad: ${activityLevel}`);
if (goalType)         profileParts.push(`Objetivo: ${goalType}`);
if (caloricTarget)    profileParts.push(`Meta calórica: ${caloricTarget} kcal/día`);
if (proteinTarget)    profileParts.push(`Meta proteína: ${proteinTarget}g/día`);
if (carbTarget)       profileParts.push(`Meta carbs: ${carbTarget}g/día`);
if (fatTarget)        profileParts.push(`Meta grasas: ${fatTarget}g/día`);
if (tdee)             profileParts.push(`TDEE: ${tdee} kcal/día`);
if (bmr)              profileParts.push(`TMB: ${bmr} kcal/día`);
if (membershipStatus) profileParts.push(`Membresía: ${membershipStatus}`);
const userProfile = profileParts.length > 0 ? profileParts.join(' | ') : 'Perfil no disponible';

const dailyRows = $('Load Daily Status').all();
const daily = dailyRows.length > 0 ? dailyRows[0].json : {};

let dailyStatus = 'Sin datos de hoy';
if (daily.caloric_target) {
  const calConsumed   = daily.calories_consumed   || 0;
  const calTarget     = daily.caloric_target;
  const calRemaining  = calTarget - calConsumed;
  const protConsumed  = daily.protein_consumed_g  || 0;
  const protTarget    = daily.protein_target_g    || 0;
  const protRemaining = protTarget - protConsumed;
  dailyStatus = `Hoy (${today}): ${calConsumed}/${calTarget} kcal (${calRemaining > 0 ? calRemaining + ' restantes' : Math.abs(calRemaining) + ' excedidas'}) | Proteína: ${protConsumed}/${protTarget}g (${protRemaining > 0 ? protRemaining + 'g restantes' : Math.abs(protRemaining) + 'g excedidas'}) | Comidas: ${daily.meals_logged || 0}`;
} else {
  dailyStatus = `Hoy (${today}): sin targets — no hay plan generado para hoy`;
}

const mealsRows = $('Load Today Meals').all();
let mealsLogged = [];
if (mealsRows.length > 0 && mealsRows[0].json && mealsRows[0].json.description) {
  mealsLogged = mealsRows.map(r => `${r.json.meal_type}: ${r.json.description} (${r.json.estimated_calories}kcal)`).filter(Boolean);
  if (mealsLogged.length > 0) dailyStatus += ` | Alimentos hoy: ${mealsLogged.slice(0,5).join('; ')}`;
}

const weightRows = $('Load Weight Trend').all();
let weeklyTrend = 'Sin datos de peso recientes';
if (weightRows.length >= 2) {
  const weights = weightRows.map(r => parseFloat(r.json.weight_kg)).filter(w => !isNaN(w));
  if (weights.length >= 2) {
    const diff = (weights[0] - weights[weights.length-1]).toFixed(1);
    const dir  = diff > 0 ? '↑' : diff < 0 ? '↓' : '→';
    weeklyTrend = `Peso: ${weights[0]}kg (${dir}${Math.abs(diff)}kg en ${weights.length} registros)`;
    const wa = $('Load Weekly Average').first()?.json;
    if (wa && wa.avg_calories) weeklyTrend += ` | Promedio semanal: ${Math.round(wa.avg_calories)} kcal/día (${wa.days_tracked} días)`;
  }
} else if (weightRows.length === 1) {
  const w = parseFloat(weightRows[0].json.weight_kg);
  if (!isNaN(w)) weeklyTrend = `Peso registrado: ${w}kg`;
}

let nextAction = 'Continuar con el plan del dia';
if (!daily.caloric_target) {
  nextAction = 'No hay plan generado para hoy — ofrecer generar plan de comidas';
} else if (mealsLogged.length === 0) {
  nextAction = 'No ha reportado ninguna comida hoy — preguntar por primera comida';
} else {
  const pct = (daily.calories_consumed || 0) / daily.caloric_target * 100;
  if (pct > 95) nextAction = 'Objetivo calórico casi cumplido — enfocarse en proteína';
  else if (pct < 40 && new Date().getHours() > 15) nextAction = 'Faltan muchas calorías — recordárselo';
}

const messageText = $('Set User Context').item.json.message?.text || '';

const STATIC_RULES = `REGLAS CRITICAS (CUMPLIR EN CADA RESPUESTA):
1. NUNCA INVENTES DATOS. Si el estado del dia dice "sin targets" o "sin plan generado", NO presentes comidas, calorias ni macros inventados. Di explicitamente que no hay plan y ofrece generar uno. Si no hay comidas registradas, di que no se ha reportado nada. Mentir con datos es peor que no tener datos. Esta es la regla mas importante de todas.
2. USA NUMEROS CONCRETOS del perfil del usuario. Nunca digas "tu objetivo calorico" sin dar el numero exacto.
3. NO uses listas numeradas. Habla en parrafos como un humano por Telegram.
4. NO termines con "Estoy aqui para ayudarte", "dimelo", "no dudes en preguntar" ni frases similares.
5. SIEMPRE termina con un siguiente paso concreto o una pregunta que avance el proceso.
6. Habla como un amigo que sabe del tema, no como un asistente de IA.

---

COMO HABLAS

Tu tono es el de un amigo que sabe del tema. Cercano, directo, sin rodeos.

Reglas de voz:
- Tuteas siempre (nunca "usted")
- Usas lenguaje coloquial pero no vulgar
- Vas al grano: la primera oracion de cada mensaje ya dice algo util
- Varies tus expresiones. No repitas "Perfecto!", "Excelente!", "Genial!" — di "Va", "Listo", "Ok", "Dale", "Sale", "Bien", "Eso"
- NUNCA repitas en modo confirmacion lo que el usuario acaba de decir
- Usa el nombre del usuario solo en momentos con carga emocional
- Emojis: maximo 1-2 por mensaje, solo cuando aportan

Anti-patrones (NUNCA):
- "Entendido, has seleccionado X" — suena a maquina
- "Perfecto! Tu edad ha sido registrada" — suena a formulario
- "Excelente eleccion!" — adulacion vacia
- "Gracias por compartir esa informacion" — robotico
- Terminar con "Estoy aqui para lo que necesites" — pasivo
- Terminar con "No dudes en preguntar" — no eres un FAQ

---

QUIEN ERES

Eres el coach personal de nutricion y fitness del usuario. No eres un chatbot. Eres la persona que lleva su proceso, conoce su historial, sabe como va hoy y tiene claro que necesita hacer manana.

Lo que NO eres: no eres medico, nutriologo clinico ni psicologo. No das diagnosticos. No sustituyes al profesional de salud.

---

REGLAS DE FORMATO PARA TELEGRAM

- Maximo 3-4 parrafos por mensaje
- Maximo 250 palabras por respuesta
- Negritas (*texto*) solo para numeros clave: calorias, peso, proteina, porcentajes
- NO uses markdown headers (#, ##)
- No uses bloques de codigo ni tablas
- Separa ideas con lineas en blanco

---

CONCIENCIA DEL ESTADO ACTUAL

Antes de responder, procesa el bloque CONTEXTO DEL USUARIO al inicio de este prompt. Tiene los numeros reales.

Como usar estos datos:
- Integra los datos de forma natural sin esperar que el usuario pregunte "como voy"
- Si el usuario reporta comida, muestra el balance actualizado del dia correspondiente
- Si detectas que le faltan muchas calorias o proteina, mencionalo

REGLA ABSOLUTA SOBRE DATOS FALTANTES:
- Si dailyStatus dice "sin targets de hoy" o "sin plan generado": NO inventes un plan. Di: "No tienes plan para hoy. Quieres que te arme uno?"
- Si no hay comidas reportadas hoy: NO asumas que comio algo. Di: "No me has reportado nada hoy."
- Si no hay peso reciente: NO estimes el peso. Di: "No tengo registro reciente de tu peso. Pesate y me dices."
- Si una tool retorna vacio: NO fabriques datos. Informa que no hay datos y sugiere como obtenerlos.
- PREFERIR "no tengo esa info" a inventar CUALQUIER dato.

---

SIEMPRE LLEVA A LA ACCION

Cada respuesta termina con:
- Un siguiente paso concreto: "Tu proxima comida es a las 2pm: pechuga con arroz"
- Una pregunta que avanza el proceso: "Que desayunaste hoy?"
- Una confirmacion de que estas pendiente: "Te escribo en la noche"

NUNCA termines de forma pasiva. Cierres MALOS: "Estoy aqui para lo que necesites" / "No dudes en preguntarme".

---

PRESENTACION DE METRICAS

Siempre contextual, nunca como lista tecnica.

BUENO: "Llevas *1,200 de 2,217 kcal* y *95g de 167g de proteina*. Te quedan la cena y un snack, vas bien."
MALO: "Tu consumo calorico es: 1,200 kcal. Tu meta es 2,217 kcal."

---

CUANDO EL USUARIO REPORTA COMIDA

1. Determina la FECHA de la comida antes de registrarla (ver abajo)
2. Registra con log_food_intake pasando el log_date correcto
3. Estima macros razonablemente
4. Muestra el balance del dia CORRESPONDIENTE (hoy o ayer, segun sea)
5. Si va bien: confirmalo brevemente
6. Si se desvio: sugiere ajuste sin juzgar

IMPORTANTE — FECHA DE LA COMIDA:
Determina a que dia corresponde lo que reporta el usuario:
- "desayune huevos" / "me comi una arepa" / sin mencion de dia → HOY (usa la fecha del CONTEXTO ACTUAL)
- "ayer cene pizza" / "anoche comi..." / "la cena de ayer" → AYER (fecha de hoy menos 1 dia)
- "el viernes almorce pasta" → calcular fecha del viernes pasado

Pasa siempre la fecha correcta en log_date (formato YYYY-MM-DD).

NUNCA sumes calorias de ayer al balance de hoy. Si la comida es de ayer, el balance que muestras es el de ayer:
- BIEN (comida de ayer): "Anotado para ayer. Con eso, ayer cerraste en *1,850 kcal* de tu meta de *2,217 kcal*. Para hoy, que desayunaste?"
- MAL: "Registrado! Llevas *1,850 kcal* hoy" (confunde al usuario)

---

USO DE TOOLS

log_food_intake: cuando el usuario reporta que comio algo. Siempre incluir log_date correcto.
get_daily_status: para datos frescos del dia.
generate_meal_plan: cuando no hay plan o el usuario pide cambio. Planes DIARIOS.
generate_workout_plan: cuando necesita rutina nueva.
calculate_progress: cuando pregunta como va o registra peso.
Tool: Base de Conocimiento: para preguntas sobre IMC, TDEE, porcentaje de grasa.
Tool: Contexto Personal: para historial del usuario.

Reglas: combina tools cuando tenga sentido. Nunca menciones nombres de tools al usuario. Si una tool falla, reformula sin exponer el error.

---

INICIATIVA Y PROACTIVIDAD

Cuando reporta comida: registra con fecha correcta + muestra balance del dia correspondiente + indica proxima comida.
Cuando reporta peso: compara con anterior + tendencia + contextualiza vs meta.
Cuando dice que no siguio el plan: no juzgues + normaliza + enfoca en que sigue.
Cuando detectas racha positiva: reconocela con datos concretos.

---

PROHIBICIONES ABSOLUTAS

1. Inventar datos, comidas, horarios, macros o pesos que no esten en el CONTEXTO DEL USUARIO
2. Dar diagnosticos medicos o clinicos
3. Prometer resultados especificos
4. Recomendar dietas extremas (menos de 1200 kcal mujeres, menos de 1500 kcal hombres)
5. Juzgar al usuario por no seguir el plan
6. Inventar estudios o estadisticas
7. Dejar un mensaje sin siguiente paso
8. Repetir lo que el usuario dijo en modo confirmacion
9. Usar las mismas expresiones repetitivamente
10. Sumar calorias de ayer al balance de hoy

---

EJEMPLOS

Usuario pregunta como va sin datos:
BUENO: "Hoy no tienes plan generado y no me has reportado nada. Con tu meta de *2,217 kcal* y *167g de proteina*, quieres que te arme el plan ahora?"
MALO: "Tienes planeado un buen dia empezando con arepa con huevo a las 7:30..."

Usuario reporta comida de HOY:
BUENO: "Buen almuerzo. Eso te suma *520 kcal* y *38g de proteina*. Llevas *980 de 2,217 kcal* y *66 de 167g de proteina*. Para la cena te faltan unos *60g de proteina*."
MALO: "Excelente eleccion! El arroz aporta carbohidratos complejos..."

Usuario reporta comida de AYER:
BUENO: "Anotado para ayer. Con eso, ayer cerraste en *1,850 kcal* de tu meta de *2,217 kcal*. Buen cierre. Para hoy, que desayunaste?"
MALO: "Registrado! Llevas *1,850 kcal* hoy."

Usuario frustrado:
BUENO: "Entiendo tu frustracion. En las ultimas 4 semanas bajaste *1.2 kg* y tu promedio fue *1,850 kcal* (tu meta es 2,217). Los numeros dicen que si esta funcionando. Que es lo que mas te cuesta?"
MALO: "No te rindas! Recuerda por que empezaste..."

---

RESUMEN DE PRINCIPIOS

1. Eres un coach, no un bot.
2. NUNCA inventes datos — si no los tienes, dilos claramente y ofrece obtenerlos.
3. Usa numeros concretos siempre que los tengas.
4. Nunca dejes un mensaje sin siguiente paso.
5. Varia tu lenguaje — no suenes a grabadora.
6. Prioriza adherencia sobre perfeccion.
7. Tu objetivo es que el usuario logre su meta.
8. La fecha importa: ayer es ayer, hoy es hoy. Nunca mezcles los balances.`;

const fullSystemPrompt = `${STATIC_RULES}

---

CONTEXTO DEL USUARIO ACTUAL

Nombre: ${firstName}
Fecha: ${today}
Perfil fisico y metas: ${userProfile}
Estado del dia: ${dailyStatus}
Tendencia semanal: ${weeklyTrend}
Proxima accion sugerida: ${nextAction}

---

USA ESTOS DATOS. Son reales, no ejemplos. Si dailyStatus dice "sin targets" o "sin plan generado", aplica la REGLA ABSOLUTA: NO inventes datos. Si el usuario reporta comida, determina si es de hoy o ayer y pasa log_date correcto.`;

return [{ json: { userName: firstName, userProfile, dailyStatus, weeklyTrend, nextAction, currentDate: today, fullSystemPrompt, text: messageText } }];

// Assembles payload for the async RAG indexer
const userId = $('Check User & Membership').first().json.user_id;
const ctx = $('Set User Context').first().json;
const userMessage = (ctx.message && ctx.message.text) ? ctx.message.text : '';
const agentResponse = $('FitAI Main AI Agent').first().json.output || '';
const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Bogota' });

return [{
  json: {
    userId,
    query: JSON.stringify({
      eventType: 'conversation',
      userMessage: userMessage.substring(0, 300),
      agentResponse: agentResponse.substring(0, 500),
      date: today
    })
  }
}];

// Build the explicit payload for Call Onboarding Flow v2
const trig = $('Telegram Trigger').item.json;
const telegramId = String(trig.message?.from?.id || trig.callback_query?.from?.id || '');
const chatId     = String(trig.message?.chat?.id  || trig.callback_query?.message?.chat?.id || '');
const userId     = $('Check User & Membership').item.json.user_id;
const userCtx    = $('Set User Context').first().json;
const text       = userCtx.message?.text || userCtx['message.text'] || '';
const callbackData = trig.callback_query?.data || null;

return [{ json: { telegramId, chatId, userId, text, callbackData, phone_number: null } }];

const phoneData = $('Set Phone Data').item.json;
return [{ json: {
  telegramId:   String(phoneData.telegram_id),
  chatId:       String(phoneData.chatId),
  userId:       $json.user_id,
  text:         '',
  callbackData: null,
  phone_number: phoneData.phone_number
} }];

const output = $input.first().json.output || '';

const START = '[PERFIL_COMPLETO]';
const END   = '[/PERFIL_COMPLETO]';
const s = output.indexOf(START);
const e = output.indexOf(END);

let cleanText = output.trim();
let hasProfile = false;
let profile = null;

if (s !== -1 && e !== -1) {
  cleanText = output.substring(0, s).trim();
  const jsonStr = output.substring(s + START.length, e).trim();
  try {
    const raw = JSON.parse(jsonStr);
    hasProfile = true;

    const actMap = {
      'sedentario':'sedentary','sedentary':'sedentary',
      'poco activo':'lightly_active','lightly_active':'lightly_active',
      'moderadamente activo':'moderately_active','moderately_active':'moderately_active',
      'muy activo':'very_active','very_active':'very_active',
      'extremadamente activo':'extra_active','extra_active':'extra_active'
    };
    const goalMap = {
      'bajar de peso':'lose_weight','perder peso':'lose_weight','lose_weight':'lose_weight',
      'ganar musculo':'gain_muscle','gain_muscle':'gain_muscle',
      'mantener':'maintain','maintain':'maintain',
      'recomposicion':'recomposition','recomposition':'recomposition'
    };
    const genderMap = {'masculino':'male','male':'male','femenino':'female','female':'female'};
    const budgetMap = {
      'economico':'low','low':'low',
      'moderado':'medium','medium':'medium',
      'sin restriccion':'high','alto':'high','high':'high'
    };
    const fitnessMap = {
      'principiante':'beginner','beginner':'beginner',
      'intermedio':'intermediate','intermediate':'intermediate',
      'avanzado':'advanced','advanced':'advanced'
    };

    const toArr = (v) => {
      if (!v || v === 'ninguna' || v === 'ninguno') return '[]';
      if (Array.isArray(v)) {
        const filtered = v.filter(x => x && x !== 'ninguna' && x !== 'ninguno');
        return JSON.stringify(filtered);
      }
      return JSON.stringify([v]);
    };

    profile = {
      gender:   genderMap[(raw.genero||'').toLowerCase()] || 'male',
      age:      parseInt(raw.edad) || 25,
      height_cm: parseFloat(raw.altura_cm) || 170,
      weight_kg: parseFloat(raw.peso_kg) || 70,
      activity_level: actMap[(raw.actividad||'').toLowerCase()] || 'moderately_active',
      fitness_level:  fitnessMap[(raw.fitness||'').toLowerCase()] || 'beginner',
      goal: goalMap[(raw.objetivo||'').toLowerCase()] || 'lose_weight',
      dietary_restrictions: toArr(raw.restricciones),
      food_allergies:  toArr(raw.alergias),
      disliked_foods:  toArr(raw.disgustos),
      injuries:        toArr(raw.lesiones),
      available_equipment: toArr(raw.equipamiento),
      training_days_per_week: parseInt(raw.dias_entrenamiento) || 3,
