      document_number: (raw.documento && raw.documento !== 'prefiero no dar') ? raw.documento : null
    };

    // Construir resumen legible del perfil para mostrar al usuario
    const goalLabels = { lose_weight:'Bajar de peso', gain_muscle:'Ganar músculo', maintain:'Mantener peso', recomposition:'Recomposición' };
    const actLabels  = { sedentary:'Sedentario', lightly_active:'Poco activo', moderately_active:'Moderadamente activo', very_active:'Muy activo', extra_active:'Extremadamente activo' };
    const fitLabels  = { beginner:'Principiante', intermediate:'Intermedio', advanced:'Avanzado' };

    const restrictions = JSON.parse(profile.dietary_restrictions);
    const restrictStr  = restrictions.length > 0 ? restrictions.join(', ') : 'Ninguna';

    const profileSummary = [
      '',
      `🎯 *Objetivo:* ${goalLabels[profile.goal] || profile.goal}`,
      `⚖️ *Peso:* ${profile.weight_kg} kg | *Altura:* ${profile.height_cm} cm`,
      `🏃 *Actividad:* ${actLabels[profile.activity_level] || profile.activity_level}`,
